codeExample1.code:
#include <stdio.h>

int main(void) {
    // 1. The 'for' loop: Definite iteration
    printf("for loop counting 1 to 3:\n");
    for (int i = 1; i <= 3; i++) {
        printf("  Iteration: %d\n", i);
    }

    // 2. The 'while' loop: Indefinite/Pre-test iteration
    printf("\nwhile loop counting down:\n");
    int count = 3;
    while (count > 0) {
        printf("  Countdown: %d\n", count);
        count--; // Critical update step
    }

    // 3. The 'do-while' loop: Post-test iteration (Guarantees >= 1 run)
    printf("\ndo-while loop executing despite false condition:\n");
    int val = 100;
    do {
        printf("  This will print exactly once. val = %d\n", val);
        val++;
    } while (val < 10); // Condition is false from the start

    return 0;
}

codeExample2.code:
#include <stdio.h>

int main(void) {
    printf("Finding and displaying prime numbers between 2 and 15:\n");

    // Outer loop selects the number to check
    for (int num = 2; num <= 15; num++) {
        int isPrime = 1; // Flag: 1 means prime

        // Inner loop checks for divisors
        for (int factor = 2; factor * factor <= num; factor++) {
            if (num % factor == 0) {
                isPrime = 0; // Not a prime
                break;       // Optimization: stop checking current number
            }
        }

        // Skip printing if not a prime
        if (!isPrime) {
            continue;
        }

        printf("%d is prime\n", num);
    }

    return 0;
}

