int compute_gcd(int a, int b) {
    if (a <= 0 || b <= 0) return 0; // Guard against negative values
    while (a != b) {
        if (a > b) {
            a = a - b;
        } else {
            b = b - a;
        }
    }
    return a;
}

#include <stdio.h>

void print_triangle(int n) {
    int current_val = 1;
    for (int i = 1; i <= n; i++) {
        // Print leading spaces
        for (int spaces = 1; spaces <= n - i; spaces++) {
            printf(" ");
        }
        // Print sequential numbers
        for (int j = 1; j <= i; j++) {
            printf("%d", current_val);
            current_val++;
        }
        printf("\n");
    }
}

questionsAndAnswers.question:
Identify and fix the bug in this attempt to print odd numbers from 1 to 5:

int i = 1;
while (i <= 5) {
    if (i == 3) {
        continue;
    }
    printf("%d ", i);
    i++;
}

questionsAndAnswers.answer:
The bug is an infinite loop. When 'i' becomes 3, the conditional check 'if (i == 3)' matches, running 'continue'. This skips 'printf' and 'i++', jumping directly back to the condition check 'while (i <= 5)'. Since 'i' remains 3, this cycle repeats indefinitely. 

To fix this, update 'i' before invoking continue:

int i = 1;
while (i <= 5) {
    if (i == 3) {
        i++; // Progress the loop control state
        continue;
    }
    printf("%d ", i);
    i++;
}

#include <stdio.h>

int get_valid_option(void) {
    int choice;
    do {
        printf("Menu Options:\n");
        printf("1. System Status\n");
        printf("2. Reboot Interface\n");
        printf("3. Shutdown\n");
        printf("Enter choices (1-3): ");

        if (scanf("%d", &choice) != 1) {
            // Clear invalid buffer input (like text letters)
            while (getchar() != '\n');
            choice = -1; // Force error state
        }

        if (choice < 1 || choice > 3) {
            printf("Invalid entry! Please input 1, 2, or 3 only.\n\n");
        }
    } while (choice < 1 || choice > 3);
    return choice;
}

#include <stdio.h>

void find_perfect_numbers(void) {
    // 1 is not perfect, begin from 2
    for (int num = 2; num <= 500; num++) {
        int divisor_sum = 1; // 1 is always a divisor

        // Optimization: loop up to square root of num
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) {
                divisor_sum += i;
                if (i * i != num) { // Avoid adding duplicate root factor
                    divisor_sum += num / i;
                }
            }
        }

        if (divisor_sum == num) {
            printf("%d is a perfect number.\n", num);
        }
    }
}

